output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?player ?playerLabel(COUNT(?match) AS ?count) WHERE {
  ?match wdt:P31 wd:Q33812353 ; wdt:P361 wd:Q1023 ; wdt:P1545 ?home ; wdt:P1546 ?away .
  VALUES(?home ?away) {(wd:Q12340 wd:Q21168)(wd:Q21168 wd:Q12340)(wd:Q1404 wd:Q3608)(wd:Q3608 wd:Q1404)(wd:Q893 wd:Q62)(wd:Q62 wd:Q893)
  }
  ?player wdt:P120 ?match ; wdt:P106 wd:Q1393800 .
  OPTIONAL {
    ?player rdfs:label ?playerLabel .
    FILTER(LANG(?playerLabel) = "en")
  }
}
GROUP BY ?player ?playerLabel
ORDER BY DESC(?count)
LIMIT 1

